#include <algorithm>

vector<int> numbers = {40, 10, 90, 25};

sort(numbers.begin(), numbers.end()); // ascending order, by default

#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

int main()
{
    vector<int> numbers = {40, 10, 90, 25};

    sort(numbers.begin(), numbers.end());

    for (int n : numbers)
    {
        cout << n << " ";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

int main()
{
    vector<int> numbers = {40, 10, 90, 25};

    sort(numbers.begin(), numbers.end(), greater<int>());

    for (int n : numbers)
    {
        cout << n << " ";
    }

    return 0;
}

vector<int> numbers = {40, 10, 90, 25, 5};

sort(numbers.begin(), numbers.begin() + 3); // only sorts indices 0, 1, 2
// numbers is now: {10, 40, 90, 25, 5} — the last two elements are untouched

